import com.pinterest.ktlint.rule.engine.core.api.ElementType.BLOCK_COMMENT
import com.pinterest.ktlint.rule.engine.core.api.ElementType.EOL_COMMENT
import com.pinterest.ktlint.rule.engine.core.api.ElementType.WHITE_SPACE
import com.pinterest.ktlint.rule.engine.core.api.firstChildLeafOrSelf
import com.pinterest.ktlint.rule.engine.core.api.indent
import com.pinterest.ktlint.rule.engine.core.api.isWhiteSpace
import com.pinterest.ktlint.rule.engine.core.api.isWhiteSpaceWithNewline
import com.pinterest.ktlint.rule.engine.core.api.nextCodeSibling
import com.pinterest.ktlint.rule.engine.core.api.nextSibling
import com.pinterest.ktlint.rule.engine.core.api.prevCodeLeaf
import com.pinterest.ktlint.rule.engine.core.api.prevLeaf
import com.pinterest.ktlint.ruleset.standard.StandardRule
import org.jetbrains.kotlin.com.intellij.lang.ASTNode
import org.jetbrains.kotlin.com.intellij.psi.PsiComment
import org.jetbrains.kotlin.com.intellij.psi.impl.source.tree.LeafPsiElement
import org.jetbrains.kotlin.com.intellij.psi.impl.source.tree.PsiWhiteSpaceImpl
import org.jetbrains.kotlin.psi.KtAnnotated
import org.jetbrains.kotlin.psi.KtBlockExpression
import org.jetbrains.kotlin.psi.KtDeclaration
import org.jetbrains.kotlin.psi.KtExpression
import org.jetbrains.kotlin.psi.KtFile
import org.jetbrains.kotlin.psi.KtPsiFactory
import org.jetbrains.kotlin.psi.psiUtil.endOffset
import org.jetbrains.kotlin.psi.psiUtil.startOffset

/**
 * Migrates deprecated ktlint suppression directives in comments (ktlint-disable / ktlint-enable) to native
 * @Suppress / @file:Suppress annotations.
 */
public class KtlintCommentDirectiveRule :
    StandardRule(
        id = "ktlint-comment-directive",
    ) {
    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        when (node.elementType) {
            EOL_COMMENT,
            BLOCK_COMMENT,
            -> {
                val directive = node.parseDirective() ?: return

                when (directive.type) {
                    DirectiveType.ENABLE -> {
                        emit(node.startOffset, ERROR_MESSAGE, true)
                        if (autoCorrect) {
                            node.removeComment()
                        }
                    }

                    DirectiveType.DISABLE -> {
                        if (node.elementType == EOL_COMMENT) {
                            val converted = node.tryConvertEolDisableDirective(autoCorrect)
                            emit(node.startOffset, ERROR_MESSAGE, converted)
                        } else {
                            val converted = node.tryConvertBlockDisableDirective(autoCorrect)
                            emit(node.startOffset, ERROR_MESSAGE, converted)
                        }
                    }
                }
            }
        }
    }

    private fun ASTNode.tryConvertEolDisableDirective(autoCorrect: Boolean): Boolean {
        val directive = parseDirective()?.takeIf { it.type == DirectiveType.DISABLE } ?: return false
        val suppressionArgs = directive.toSuppressAnnotationArgs()

        val prevLeaf = prevCodeLeaf() ?: return false
        val targetPsi =
            prevLeaf
                .psi
                .findSuppressTargetPsi(commentStartOffset = startOffset)
                ?: return false

        if (!autoCorrect) {
            return true
        }

        addSuppressAnnotationIfMissing(targetPsi, suppressionArgs)
        removeComment()
        return true
    }

    private fun ASTNode.tryConvertBlockDisableDirective(autoCorrect: Boolean): Boolean {
        val directive = parseDirective()?.takeIf { it.type == DirectiveType.DISABLE } ?: return false
        val suppressionArgs = directive.toSuppressAnnotationArgs()

        // Convert to @file:Suppress(...) when used at the top of the file
        val ktFile = treeParent?.psi as? KtFile
        if (ktFile != null && prevCodeLeaf() == null) {
            if (!autoCorrect) {
                return true
            }
            addFileSuppressAnnotationIfMissing(ktFile, suppressionArgs)
            removeComment()
            return true
        }

        // Convert disable/enable block around a single construct
        val target = nextCodeSibling() ?: return false
        val nextNonWhitespaceSibling =
            target
                .nextSibling { !it.isWhiteSpace() }
                ?: return false
        val enableDirective =
            nextNonWhitespaceSibling
                .takeIf { it.psi is PsiComment }
                ?.parseDirective()
                ?.takeIf { it.type == DirectiveType.ENABLE && it.ruleIds == directive.ruleIds }
        if (enableDirective == null) {
            return false
        }

        if (!autoCorrect) {
            return true
        }

        val targetPsi = target.psi
        addSuppressAnnotationIfMissing(targetPsi, suppressionArgs)
        removeComment()
        nextNonWhitespaceSibling.removeComment()
        return true
    }

    private fun addSuppressAnnotationIfMissing(
        targetPsi: org.jetbrains.kotlin.com.intellij.psi.PsiElement,
        suppressionArgs: List<String>,
    ) {
        val ktAnnotated = targetPsi as? KtAnnotated
        if (ktAnnotated != null && ktAnnotated.isAlreadySuppressed(suppressionArgs)) {
            return
        }

        val targetNode = targetPsi.node
        val leaf = targetNode.firstChildLeafOrSelf().psi as LeafPsiElement
        val psiFactory = KtPsiFactory(targetPsi.project, false)
        val annotationEntry = psiFactory.createAnnotationEntry("@Suppress(${suppressionArgs.joinToString { \"\"\"\"$it\"\"\"\" }})")

        leaf.rawInsertBeforeMe(annotationEntry)
        leaf.rawInsertBeforeMe(PsiWhiteSpaceImpl(targetNode.indent()))
    }

    private fun addFileSuppressAnnotationIfMissing(
        ktFile: KtFile,
        suppressionArgs: List<String>,
    ) {
        val fileAnnotationList = ktFile.fileAnnotationList
        if (fileAnnotationList != null && fileAnnotationList.isAlreadySuppressed(suppressionArgs)) {
            return
        }

        val psiFactory = KtPsiFactory(ktFile.project, false)
        val fileSuppressAnnotationEntry =
            psiFactory.createAnnotationEntry(
                "@file:Suppress(${suppressionArgs.joinToString { \"\"\"\"$it\"\"\"\" }})",
            )

        if (fileAnnotationList == null) {
            val anchor =
                ktFile.packageDirective
                    ?: ktFile.importList
                    ?: ktFile.firstChild
            ktFile.addBefore(fileSuppressAnnotationEntry, anchor)
            ktFile.addBefore(PsiWhiteSpaceImpl("\n\n"), anchor)
        } else {
            val lastEntry = fileAnnotationList.annotationEntries.lastOrNull()
            if (lastEntry == null) {
                fileAnnotationList.add(fileSuppressAnnotationEntry)
                fileAnnotationList.add(PsiWhiteSpaceImpl("\n"))
            } else {
                fileAnnotationList.addAfter(fileSuppressAnnotationEntry, lastEntry)
                fileAnnotationList.addAfter(PsiWhiteSpaceImpl("\n"), fileSuppressAnnotationEntry)
            }
        }
    }

    private fun org.jetbrains.kotlin.com.intellij.psi.PsiElement.findSuppressTargetPsi(commentStartOffset: Int): org.jetbrains.kotlin.com.intellij.psi.PsiElement? {
        // Prefer annotating a declaration on the same line as the directive
        val declaration =
            generateSequence(this) { it.parent }
                .filterIsInstance<KtDeclaration>()
                .firstOrNull { it.endOffset <= commentStartOffset }
        if (declaration != null) {
            return declaration
        }

        // Fallback: annotate expression statements in blocks
        val expression =
            generateSequence(this) { it.parent }
                .filterIsInstance<KtExpression>()
                .firstOrNull { it.parent is KtBlockExpression && it.endOffset <= commentStartOffset }
        return expression
    }

    private fun KtAnnotated.isAlreadySuppressed(suppressionArgs: List<String>): Boolean {
        val existingArgs =
            annotationEntries
                .filter {
                    it.calleeExpression?.constructorReferenceExpression?.getReferencedName() in SUPPRESS_ANNOTATIONS
                }.flatMap { it.valueArguments }
                .mapNotNull { it.getArgumentExpression()?.text?.removeSurrounding("\"") }
                .toSet()

        return existingArgs.contains("ktlint") || suppressionArgs.all(existingArgs::contains)
    }

    private fun ASTNode.removeComment() {
        // Remove whitespace preceding an EOL comment so that we do not end up with trailing spaces
        val prevLeaf = prevLeaf()
        if (prevLeaf?.elementType == WHITE_SPACE && !prevLeaf.textContains('\n')) {
            (prevLeaf.psi as LeafPsiElement).rawRemove()
        }
        (psi as LeafPsiElement).rawRemove()
    }

    private fun ASTNode.parseDirective(): Directive? {
        val rawContent =
            when {
                elementType == EOL_COMMENT -> text.removePrefix("//")
                elementType == BLOCK_COMMENT -> text.removePrefix("/*").removeSuffix("*/")
                else -> return null
            }

        val parts = rawContent.trim().split(Regex("\\s+")).filter { it.isNotBlank() }
        if (parts.isEmpty()) {
            return null
        }

        val type =
            when (parts[0]) {
                KTLINT_DISABLE -> DirectiveType.DISABLE
                KTLINT_ENABLE -> DirectiveType.ENABLE
                else -> return null
            }

        return Directive(type, parts.drop(1))
    }

    private fun Directive.toSuppressAnnotationArgs(): List<String> {
        if (ruleIds.isEmpty()) {
            return listOf("ktlint")
        }
        return ruleIds
            .map { it.normalizeRuleIdForSuppressAnnotation() }
            .map { "ktlint:$it" }
    }

    private fun String.normalizeRuleIdForSuppressAnnotation(): String {
        // Migration: the old 'experimental' rule set id has been replaced by 'standard'
        return when {
            startsWith("experimental:") -> removePrefix("experimental:")
            startsWith("standard:") -> removePrefix("standard:")
            else -> this
        }
    }

    private data class Directive(
        val type: DirectiveType,
        val ruleIds: List<String>,
    )

    private enum class DirectiveType {
        DISABLE,
        ENABLE,
    }

    private companion object {
        const val KTLINT_DISABLE = "ktlint-disable"
        const val KTLINT_ENABLE = "ktlint-enable"

        val SUPPRESS_ANNOTATIONS = setOf("Suppress", "SuppressWarnings")

        const val ERROR_MESSAGE =
            "Ktlint suppression directives in comments (ktlint-disable / ktlint-enable) are deprecated. Replace them with @Suppress annotations."
    }
}
