import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class KtlintCommentDirectiveRuleTest {
    private val ktlintCommentDirectiveRuleAssertThat = assertThatRule { KtlintCommentDirectiveRule() }

    @Test
    fun `Given an EOL ktlint-disable directive then it is replaced with a Suppress annotation`() {
        val code =
            """
            fun foo() {
                val foo = \"foo\" // ktlint-disable
            }
            """.trimIndent()

        val formattedCode =
            """
            fun foo() {
                @Suppress(\"ktlint\")
                val foo = \"foo\"
            }
            """.trimIndent()

        ktlintCommentDirectiveRuleAssertThat(code)
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given an EOL ktlint-disable directive for an experimental rule then it is replaced with a standard suppression`() {
        val code =
            """
            fun foo() {
                val foo = \"foo\" // ktlint-disable experimental:argument-list-wrapping
            }
            """.trimIndent()

        val formattedCode =
            """
            fun foo() {
                @Suppress(\"ktlint:argument-list-wrapping\")
                val foo = \"foo\"
            }
            """.trimIndent()

        ktlintCommentDirectiveRuleAssertThat(code)
            .isFormattedAs(formattedCode)
    }
}
"}

