278→private fun ASTNode.replaceWhitespaceWith(text: String) {
279→    require(this.elementType == WHITE_SPACE)
280→    if (this.text != text) {
281→        (this.psi as LeafElement).rawReplaceWithText(text)
282→    }
283→}
284→
285→/**
286→ * Updates or inserts a new whitespace element with [text] after the given node. If the node itself is a whitespace
287→ * then its contents is replaced with [text]. If the node is a (nested) composite element, the whitespace element is
288→ * added after the last child leaf.
289→ */
290→public fun ASTNode.upsertWhitespaceAfterMe(text: String) {
291→    if (this is LeafElement) {
292→        if (this.elementType == WHITE_SPACE) {
293→            return replaceWhitespaceWith(text)
294→        }
295→        val next = treeNext ?: nextLeaf()
296→        if (next != null && next.elementType == WHITE_SPACE) {
297→            next.replaceWhitespaceWith(text)
298→        } else {
299→            PsiWhiteSpaceImpl(text).also { psiWhiteSpace ->
300→                (psi as LeafElement).rawInsertAfterMe(psiWhiteSpace)
301→            }
302→        }
303→    } else {
304→        lastChildLeafOrSelf().upsertWhitespaceAfterMe(text)
305→    }
306→}
