182→    private fun org.jetbrains.kotlin.com.intellij.psi.PsiElement.findSuppressTargetPsi(commentStartOffset: Int): org.jetbrains.kotlin.com.intellij.psi.PsiElement? {
183→        // Prefer annotating a declaration on the same line as the directive
184→        val declaration =
185→            generateSequence(this) { it.parent }
186→                .filterIsInstance<KtDeclaration>()
187→                .firstOrNull { it.endOffset <= commentStartOffset }
188→        if (declaration != null) {
