192→        // Fallback: annotate expression statements in blocks
193→        val expression =
194→            generateSequence(this) { it.parent }
195→                .filterIsInstance<KtExpression>()
196→                .firstOrNull { it.parent is KtBlockExpression && it.endOffset <= commentStartOffset }
