221→    private fun ASTNode.parseDirective(): Directive? {
222→        val rawContent =
223→            when {
224→                elementType == EOL_COMMENT -> text.removePrefix("//")
225→                elementType == BLOCK_COMMENT -> text.removePrefix("/*").removeSuffix("*/")
226→                else -> return null
227→            }
228→
229→        val parts = rawContent.trim().split(Regex("\\s+")).filter { it.isNotBlank() }
230→        if (parts.isEmpty()) {
