class KtlintCommentDirectiveRuleTest {
    private val ktlintCommentDirectiveRuleAssertThat = assertThatRule { KtlintCommentDirectiveRule() }

    @Test
    fun `Given an EOL ktlint-disable directive then it is replaced with a Suppress annotation`() {
        val code =
            """
            fun foo() {
                val foo = \"foo\" // ktlint-disable
            }
            """.trimIndent()

